function useCountUp(target,dur=900){const[v,setV]=useState(0);const r=useRef(0);
  useEffect(()=>{let raf;const f=r.current,s=performance.now();const tick=(now)=>{const p=Math.min(1,(now-s)/dur);const e=1-Math.pow(1-p,3);const c=f+(target-f)*e;r.current=c;setV(c);if(p<1)raf=requestAnimationFrame(tick);};raf=requestAnimationFrame(tick);return()=>cancelAnimationFrame(raf);},[target,dur]);return v;}
