      {auth==="register" && <AuthPage mode="register" dark={dark} toggleTheme={toggleTheme} go={setAuth} setUser={setUser}/>}
      {auth==="logoff"   && <Logoff go={setAuth}/>}
      {auth==="app"      && <OS {...themeProps} user={user} setUser={setUser} logout={()=>setAuth("logoff")}/>}
